import { type CreateTask, type UpdateTask } from 'wasp/server/actions'
import { HttpError } from 'wasp/server'

type CreateTaskArgs = {
  description: string
}

export const createTask: CreateTask<CreateTaskArgs, any> = async (args, context) => {
  if (!context.user) {
    throw new HttpError(401)
  }
  return context.entities.Task.create({
    data: {
      description: args.description,
      user: { connect: { id: context.user.id } },
    },
  })
}

type UpdateTaskArgs = {
