import { useQuery, useAction, getTasks, createTask, updateTask } from 'wasp/client/operations'
import { logout } from 'wasp/client/auth'
import './Main.css'

export function MainPage() {
  const { data: tasks, isLoading, error } = useQuery(getTasks)
  const createTaskAction = useAction(createTask)
  const updateTaskAction = useAction(updateTask)

  if (isLoading) return 'Loading...'
  if (error) return 'Error: ' + error

  const handleSubmit = async (event: any) => {
    event.preventDefault()
    try {
      const description = event.target.description.value
      event.target.description.value = ''
      await createTaskAction({ description })
    } catch (err: any) {
      window.alert('Error: ' + err.message)
    }
  }

  const handleToggleTask = async (task: any) => {
    try {
      await updateTaskAction({ id: task.id, isDone: !task.isDone })
    } catch (err: any) {
      window.alert('Error: ' + err.message)
    }
  }

  return (
    <div className="container" style={{ padding: '20px', maxWidth: '600px', margin: '0 auto' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <h1>Todo List</h1>
        <button onClick={logout} className="button button-outlined">Logout</button>
      </div>

      <form onSubmit={handleSubmit} style={{ marginBottom: '20px' }}>
        <input name="description" placeholder="New Task Description" required style={{ padding: '8px', marginRight: '8px', width: '70%' }} />
        <button type="submit" className="button button-filled">Add Task</button>
      </form>

      {tasks && tasks.length > 0 ? (
        <ul style={{ listStyle: 'none', padding: 0 }}>
          {tasks.map((task: any) => (
            <li key={task.id} style={{ marginBottom: '10px', display: 'flex', alignItems: 'center' }}>
              <input
                type="checkbox"
                checked={task.isDone}
                onChange={() => handleToggleTask(task)}
                style={{ marginRight: '10px' }}
              />
              <span style={{ textDecoration: task.isDone ? 'line-through' : 'none' }}>
                {task.description}
              </span>
            </li>
          ))}
        </ul>
      ) : (
        <p>No tasks yet. Add one above!</p>
      )}
    </div>
  )
}

